 16→// ── Bundled font setup for Sharp/librsvg SVG text rendering ──
 17→const __filename = fileURLToPath(import.meta.url);
 18→const __dirname = dirname(__filename);
 19→const FONT_DIR = join(__dirname, '.fonts');
 20→const FONT_PATH = join(FONT_DIR, 'DejaVuSans.ttf');
 21→const FONT_BOLD_PATH = join(FONT_DIR, 'DejaVuSans-Bold.ttf');
 22→let fontsReady = false;
 23→
 24→async function ensureShareFonts() {
 25→    if (fontsReady) return;
 26→    try {
 27→        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
 28→
 29→        const downloads = [];
 30→        if (!existsSync(FONT_PATH)) {
 31→            downloads.push(
 32→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
 33→                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 34→                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
 35→            );
 36→        }
 37→        if (!existsSync(FONT_BOLD_PATH)) {
 38→            downloads.push(
 39→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
 40→                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 41→                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
 42→            );
 43→        }
 44→        if (downloads.length) await Promise.all(downloads);
 45→
 46→        fontsReady = true;
 47→        console.log('Share fonts ready:', FONT_DIR);
 48→    } catch (err) {
 49→        console.error('Failed to setup share fonts:', err?.message || err);
 50→    }
 51→}
