 53→const app = express();
 54→const PORT = process.env.PORT || 3000;
 55→const SITE_URL = SITE_URL_SHARED;
 56→const DEFAULT_OG_IMAGE_URL = `${SITE_URL}/assets/no-image.png`;
 57→const DEFAULT_OG_IMAGE_WIDTH = 1200;
 58→const DEFAULT_OG_IMAGE_HEIGHT = 630;
 59→const SOCIAL_PREVIEW_MAX_CHARS = 160;
 60→const REMOTE_IMAGE_FETCH_TIMEOUT_MS = 7000;
 61→const REMOTE_IMAGE_MAX_BYTES = 15 * 1024 * 1024;
 62→const SHARE_IMAGE_FETCH_USER_AGENT = 'IskrybShareBot/1.0 (+https://iskrib.com)';
 63→const META_FB_APP_ID = (process.env.META_FB_APP_ID || process.env.FB_APP_ID || process.env.VITE_FB_APP_ID || '').trim();
 64→const SHARE_IMAGE_DEBUG = false;
 65→const SUPABASE_URL = (process.env.SUPABASE_URL || '').trim();
