 67→const normalizeWhitespace = (value) => String(value ?? '')
 68→    .replace(/\s+/g, ' ')
 69→    .trim();
 70→
 71→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 72→    const normalized = normalizeWhitespace(value);
 73→    if (!normalized) return '';
 74→    if (normalized.length <= maxLength) return normalized;
 75→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 76→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 77→};
