 87→const getRequestOrigin = (req) => {
 88→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 89→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 90→    const host = forwardedHost || req.get('host') || '';
 91→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 92→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 93→        ? forwardedProto
 94→        : requestProtocol === 'http' || requestProtocol === 'https'
 95→            ? requestProtocol
 96→            : 'https';
 97→
 98→    if (!host) {
 99→        return SITE_URL;
100→    }
101→
102→    return `${protocol}://${host}`;
103→};
