105→const pickFirstNonEmptyString = (...values) => {
106→    for (const value of values) {
107→        if (typeof value === 'string') {
108→            const trimmed = value.trim();
109→            if (trimmed) return trimmed;
110→        }
111→    }
112→    return '';
113→};
114→
115→const parseImageDimension = (value) => {
116→    const parsed = Number(value);
117→    if (!Number.isFinite(parsed)) return undefined;
118→    return parsed;
119→};
120→
121→const imageFromNodeLike = (nodeLike) => {
122→    if (!nodeLike || typeof nodeLike !== 'object') return null;
123→
124→    const src = pickFirstNonEmptyString(
125→        nodeLike.src,
126→        nodeLike.url,
127→        nodeLike.image_url,
128→        nodeLike.imageUrl,
129→        nodeLike?.payload?.src,
130→        nodeLike?.data?.src
131→    );
132→    if (!src) return null;
133→
134→    return {
135→        src,
136→        width: parseImageDimension(nodeLike.width),
137→        height: parseImageDimension(nodeLike.height),
138→    };
139→};
