204→const buildShareMetaFromJournal = (journal) => {
205→    const lexicalData = extractFromLexical(journal?.content);
206→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
207→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
208→    const title = normalizedTitle || 'Untitled Post';
209→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
210→
211→    let description = lexicalData.text || '';
212→    if (!description && canvasData.text) {
213→        description = canvasData.text;
214→    }
215→    if (!description) {
216→        description = `Read "${title}" by ${authorName} on Iskryb`;
217→    }
218→
219→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
220→    let imageCandidateSource = 'fallback';
221→    if (lexicalData.image?.src) {
222→        imageCandidate = lexicalData.image.src;
223→        imageCandidateSource = 'lexical';
224→    } else if (canvasData.image?.src) {
225→        imageCandidate = canvasData.image.src;
226→        imageCandidateSource = 'canvas';
227→    } else if (journal?.users?.image_url) {
228→        imageCandidate = journal.users.image_url;
229→        imageCandidateSource = 'author_avatar';
230→    }
231→
232→    return {
233→        title,
234→        normalizedTitle,
235→        description: toPreviewText(description),
236→        imageCandidate,
237→        imageCandidateSource
238→    };
239→};
