241→const resolveAbsoluteHttpUrl = (rawUrl) => {
242→    try {
243→        const raw = String(rawUrl || '').trim();
244→        if (!raw) return null;
245→
246→        const isSupabasePath =
247→            raw.startsWith('/storage/v1/object/public/')
248→            || raw.startsWith('storage/v1/object/public/');
249→
250→        const baseUrl = isSupabasePath && SUPABASE_URL
251→            ? `${SUPABASE_URL}/`
252→            : SITE_URL;
253→
254→        const parsed = new URL(raw, baseUrl);
255→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
256→            return null;
257→        }
258→        return parsed.toString();
259→    } catch {
260→        return null;
261→    }
262→};
