264→const isPrivateIpv4Address = (ip) => {
265→    const parts = ip.split('.').map((part) => Number(part));
266→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
267→        return true;
268→    }
269→
270→    const [a, b] = parts;
271→    if (a === 10 || a === 127 || a === 0) return true;
272→    if (a === 169 && b === 254) return true;
273→    if (a === 172 && b >= 16 && b <= 31) return true;
274→    if (a === 192 && b === 168) return true;
275→    return false;
276→};
277→
278→const isPrivateIpv6Address = (ip) => {
279→    const normalized = ip.toLowerCase();
280→    return (
281→        normalized === '::1' ||
282→        normalized.startsWith('fc') ||
283→        normalized.startsWith('fd') ||
284→        normalized.startsWith('fe80:')
285→    );
286→};
287→
288→const isPrivateIpAddress = (ip) => {
289→    const ipVersion = net.isIP(ip);
290→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
291→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
292→    return true;
293→};
