421→const convertToOgJpeg = async (inputBuffer) => {
422→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
423→        .rotate()
424→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
425→            fit: 'contain',
426→            background: { r: 255, g: 255, b: 255, alpha: 1 },
427→        })
428→        .jpeg({ quality: 82, mozjpeg: true })
429→        .toBuffer();
430→};
