473→app.use((req, res, next) => {
474→    if (req.method === "GET" && !req.headers.authorization) {
475→        // no-cache: browser must revalidate with server before using cached response.
476→        // This prevents stale data after mutations (likes, comments, replies, etc.)
477→        // while still allowing conditional requests (304 Not Modified) for performance.
478→        // React Query handles client-side caching, so browser cache is unnecessary.
479→        res.set("Cache-Control", "no-cache");
480→    }
481→    next();
482→});
