487→// ── Profile share route: composite OG image for social media ──
488→app.get('/share/u/:username/image', async (req, res) => {
489→    const { username } = req.params;
490→    await ensureShareFonts();
491→
492→    try {
493→        const result = await getUserByUsernameService(username);
494→        const user = result?.userData?.[0];
495→        if (!user) {
496→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
497→        }
498→
499→        const displayName = normalizeWhitespace(user.name) || username;
500→        const handle = `@${normalizeWhitespace(user.username || username)}`;
501→        const bio = toPreviewText(user.bio || '', 120);
502→
503→        // ── Fetch background image ──
504→        let bgBuffer = null;
505→        const bgStyle = user.background || {};
506→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
507→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
508→            : null;
509→        const bgImageUrl = bgImageMatch?.[1];
510→
511→        if (bgImageUrl) {
512→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
513→            if (bgEval.ok && bgEval.resolvedUrl) {
514→                try {
515→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
516→                    bgBuffer = remote.buffer;
517→                } catch { /* use fallback gradient */ }
518→            }
519→        }
520→
521→        // ── Base layer: background or dark gradient ──
522→        let baseLayer;
523→        if (bgBuffer) {
524→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
525→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
526→                .toBuffer();
527→        } else {
528→            // Use profile's solid background color if available, otherwise dark fallback
529→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
530→                ? bgStyle.background.trim()
531→                : null;
532→            const gradientSvg = solidColor
533→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
534→                    <rect width="100%" height="100%" fill="${solidColor}"/>
535→                </svg>`
536→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
537→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
538→                        <stop offset="0%" stop-color="#1a1a2e"/>
539→                        <stop offset="100%" stop-color="#16213e"/>
540→                    </linearGradient></defs>
541→                    <rect width="100%" height="100%" fill="url(#g)"/>
542→                </svg>`;
543→            baseLayer = await sharp(Buffer.from(gradientSvg))
544→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
545→                .png()
546→                .toBuffer();
547→        }
548→
549→        // ── Dark overlay for text readability ──
550→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
551→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
552→        </svg>`;
553→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
554→
555→        // ── Circular avatar ──
556→        let avatarComposite = null;
557→        const avatarSize = 180;
558→        const avatarUrl = user.image_url;
559→        if (avatarUrl) {
560→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
561→            if (avatarEval.ok && avatarEval.resolvedUrl) {
562→                try {
563→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
564→                    const circleMask = Buffer.from(
565→                        `<svg width="${avatarSize}" height="${avatarSize}">
566→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
567→                        </svg>`
568→                    );
569→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
570→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
571→                        .png()
572→                        .toBuffer();
573→                    const circularAvatar = await sharp(resizedAvatar)
574→                        .composite([{ input: circleMask, blend: 'dest-in' }])
575→                        .png()
576→                        .toBuffer();
577→                    avatarComposite = circularAvatar;
578→                } catch { /* skip avatar */ }
579→            }
580→        }
581→
582→        // ── Compose all layers ──
583→        const composites = [
584→            { input: overlayBuffer, top: 0, left: 0 },
585→        ];
586→
587→        if (avatarComposite) {
588→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
589→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
590→        }
591→
592→        const finalImage = await sharp(baseLayer)
593→            .composite(composites)
594→            .jpeg({ quality: 82, mozjpeg: true })
595→            .toBuffer();
596→
597→        res.set('Content-Type', 'image/jpeg');
598→        res.set('Cache-Control', 'public, max-age=3600');
599→        return res.send(finalImage);
600→    } catch (err) {
601→        console.error('profile share image route error:', err?.message || err);
602→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
603→    }
604→});
