606→// ── Profile share route: serves OG meta tags for social media previews ──
607→app.get('/share/u/:username', async (req, res) => {
608→    const { username } = req.params;
609→    const shareOrigin = getRequestOrigin(req);
610→    const clientProfileUrl = `${SITE_URL}/u/${encodeURIComponent(username)}`;
611→
612→    try {
613→        const result = await getUserByUsernameService(username);
614→        const user = result?.userData?.[0];
615→        if (!user) {
616→            return res.redirect(302, clientProfileUrl);
